import{_ as a,c as o,o as r,a1 as i}from"./chunks/framework.DILC4Csi.js";const l=JSON.parse('{"title":"Privacidade: Proteção de Dados | opencode-supermemory","description":"Entenda os mecanismos de privacidade do opencode-supermemory. Aprenda a usar tags private para anonimizar dados e configurar API Key com segurança.","frontmatter":{"title":"Privacidade: Proteção de Dados | opencode-supermemory","sidebarTitle":"Privacidade","subtitle":"Privacidade e Segurança de Dados: Como Proteger Suas Informações Sensíveis","description":"Entenda os mecanismos de privacidade do opencode-supermemory. Aprenda a usar tags private para anonimizar dados e configurar API Key com segurança.","tags":["privacidade","segurança","configuração"],"prerequisite":["start-getting-started"],"order":1},"headers":[],"relativePath":"pt/supermemoryai/opencode-supermemory/security/privacy/index.md","filePath":"pt/supermemoryai/opencode-supermemory/security/privacy/index.md"}'),n={name:"pt/supermemoryai/opencode-supermemory/security/privacy/index.md"};function s(t,e,d,c,m,u){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="privacidade-e-seguranca-de-dados-como-proteger-suas-informacoes-sensiveis" tabindex="-1">Privacidade e Segurança de Dados: Como Proteger Suas Informações Sensíveis <a class="header-anchor" href="#privacidade-e-seguranca-de-dados-como-proteger-suas-informacoes-sensiveis" aria-label="Permalink to &quot;Privacidade e Segurança de Dados: Como Proteger Suas Informações Sensíveis&quot;">​</a></h1><h2 id="o-que-voce-vai-aprender" tabindex="-1">O Que Você Vai Aprender <a class="header-anchor" href="#o-que-voce-vai-aprender" aria-label="Permalink to &quot;O Que Você Vai Aprender&quot;">​</a></h2><ul><li><strong>Entender para onde vão os dados</strong>: Saiba claramente quais dados serão enviados para a nuvem e quais ficarão localmente.</li><li><strong>Dominar técnicas de anonimização</strong>: Aprenda a usar tags <code>&lt;private&gt;</code> para evitar que informações sensíveis (como senhas, chaves) sejam enviadas.</li><li><strong>Gerenciar chaves com segurança</strong>: Aprenda a configurar <code>SUPERMEMORY_API_KEY</code> da forma mais segura.</li></ul><h2 id="ideia-central" tabindex="-1">Ideia Central <a class="header-anchor" href="#ideia-central" aria-label="Permalink to &quot;Ideia Central&quot;">​</a></h2><p>Ao usar o opencode-supermemory, entender o fluxo de dados é crucial:</p><ol><li><strong>Armazenamento na nuvem</strong>: Suas memórias (Memories) são armazenadas no banco de dados na nuvem do Supermemory, não em arquivos locais. Isso significa que você precisa de conexão de rede para acessar memórias.</li><li><strong>Anonimização local</strong>: Para proteger a privacidade, o plugin realiza anonimização localmente <strong>antes</strong> de enviar dados para a nuvem.</li><li><strong>Controle explícito</strong>: O plugin não varre todos os arquivos automaticamente para enviar; somente quando o Agent chama explicitamente a ferramenta <code>add</code> ou aciona a compactação, o conteúdo relevante será processado.</li></ol><h3 id="mecanismo-de-anonimizacao" tabindex="-1">Mecanismo de Anonimização <a class="header-anchor" href="#mecanismo-de-anonimizacao" aria-label="Permalink to &quot;Mecanismo de Anonimização&quot;">​</a></h3><p>O plugin vem com um filtro simples, especificamente para identificar tags <code>&lt;private&gt;</code>.</p><ul><li><strong>Entrada</strong>: <code>A senha do banco de dados aqui é &lt;private&gt;123456&lt;/private&gt;</code></li><li><strong>Processamento</strong>: O plugin detecta a tag, substitui seu conteúdo por <code>[REDACTED]</code>.</li><li><strong>Envio</strong>: <code>A senha do banco de dados aqui é [REDACTED]</code></li></ul><div class="info custom-block"><p class="custom-block-title">Dica</p><p>Este processo ocorre no código interno do plugin, antes que os dados saiam do seu computador.</p></div><h2 id="siga-me" tabindex="-1">Siga-me <a class="header-anchor" href="#siga-me" aria-label="Permalink to &quot;Siga-me&quot;">​</a></h2><h3 id="passo-1-configurar-api-key-com-seguranca" tabindex="-1">Passo 1: Configurar API Key com Segurança <a class="header-anchor" href="#passo-1-configurar-api-key-com-seguranca" aria-label="Permalink to &quot;Passo 1: Configurar API Key com Segurança&quot;">​</a></h3><p>Embora você possa escrever a API Key diretamente no arquivo de configuração, para evitar vazamento acidental (como compartilhar acidentalmente o arquivo de configuração com outros), recomendamos entender a lógica de prioridade.</p><p><strong>Regras de prioridade</strong>:</p><ol><li><strong>Arquivo de configuração</strong> (<code>~/.config/opencode/supermemory.jsonc</code>): Prioridade mais alta.</li><li><strong>Variável de ambiente</strong> (<code>SUPERMEMORY_API_KEY</code>): Se não definido no arquivo de configuração, usa esta variável.</li></ol><p><strong>Prática recomendada</strong>: Se você deseja alternar de forma flexível ou usar em ambiente CI/CD, use variáveis de ambiente. Se você é um desenvolvedor pessoal, configurar no arquivo JSONC do diretório do usuário também é seguro (porque não está no repositório Git do seu projeto).</p><h3 id="passo-2-usar-tag-private" tabindex="-1">Passo 2: Usar Tag <code>&lt;private&gt;</code> <a class="header-anchor" href="#passo-2-usar-tag-private" aria-label="Permalink to &quot;Passo 2: Usar Tag `&lt;private&gt;`&quot;">​</a></h3><p>Quando você faz o Agent lembrar certos conteúdos contendo informações sensíveis por meio de linguagem natural na conversa, pode usar a tag <code>&lt;private&gt;</code> para envolver partes sensíveis.</p><p><strong>Demonstração de operação</strong>:</p><p>Diga ao Agent:</p><blockquote><p>Lembre-se, o IP do banco de dados de produção é 192.168.1.10, mas a senha root é <code>&lt;private&gt;SenhaSecreta!&lt;/private&gt;</code>, não vaze a senha.</p></blockquote><p><strong>Você deve ver</strong>: O Agent chamará a ferramenta <code>supermemory</code> para salvar a memória. Embora a resposta do Agent possa conter a senha (porque ela está no contexto), a <strong>memória real salva na nuvem do Supermemory</strong> já foi anonimizada.</p><h3 id="passo-3-verificar-resultado-da-anonimizacao" tabindex="-1">Passo 3: Verificar Resultado da Anonimização <a class="header-anchor" href="#passo-3-verificar-resultado-da-anonimizacao" aria-label="Permalink to &quot;Passo 3: Verificar Resultado da Anonimização&quot;">​</a></h3><p>Podemos verificar por meio de busca se a senha realmente não foi salva.</p><p><strong>Operação</strong>: Faça o Agent buscar a memória que acabamos de criar:</p><blockquote><p>Busque a senha do banco de dados de produção.</p></blockquote><p><strong>Resultado esperado</strong>: O conteúdo que o Agent recupera do Supermemory deve ser: <code>O IP do banco de dados de produção é 192.168.1.10, mas a senha root é [REDACTED]...</code></p><p>Se o Agent disser &quot;a senha é [REDACTED]&quot;, isso significa que o mecanismo de anonimização está funcionando normalmente.</p><h2 id="equivocos-comuns" tabindex="-1">Equívocos Comuns <a class="header-anchor" href="#equivocos-comuns" aria-label="Permalink to &quot;Equívocos Comuns&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Equívoco 1: Todo o código será enviado</p><p><strong>Fato</strong>: O plugin <strong>não</strong> envia automaticamente todo o seu repositório de código. Ele só envia aquele segmento específico quando executa <code>/supermemory-init</code> para varredura de inicialização, ou quando o Agent decide explicitamente &quot;lembrar&quot; alguma lógica de código.</p></div><div class="warning custom-block"><p class="custom-block-title">Equívoco 2: Arquivo .env será carregado automaticamente</p><p><strong>Fato</strong>: O plugin lê <code>SUPERMEMORY_API_KEY</code> do ambiente do processo. Se você colocar um arquivo <code>.env</code> no diretório raiz do projeto, o plugin <strong>não</strong> o lê automaticamente, a menos que o terminal ou programa principal OpenCode que você usa o carregue.</p></div><h2 id="apendice-referencia-de-codigo-fonte" tabindex="-1">Apêndice: Referência de Código-fonte <a class="header-anchor" href="#apendice-referencia-de-codigo-fonte" aria-label="Permalink to &quot;Apêndice: Referência de Código-fonte&quot;">​</a></h2><details><summary><strong>Clique para expandir e ver a localização do código-fonte</strong></summary><blockquote><p>Última atualização: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funcionalidade</th><th>Caminho do Arquivo</th><th>Linha</th></tr></thead><tbody><tr><td>Lógica de anonimização de privacidade</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/services/privacy.ts#L1-L13" target="_blank" rel="noreferrer"><code>src/services/privacy.ts</code></a></td><td>1-13</td></tr><tr><td>Carregamento de API Key</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/config.ts#L90" target="_blank" rel="noreferrer"><code>src/config.ts</code></a></td><td>90</td></tr><tr><td>Anonimização na chamada do plugin</td><td><a href="https://github.com/supermemoryai/opencode-supermemory/blob/main/src/index.ts#L282" target="_blank" rel="noreferrer"><code>src/index.ts</code></a></td><td>282</td></tr></tbody></table><p><strong>Funções-chave</strong>:</p><ul><li><code>stripPrivateContent(content)</code>: Executa substituição regex, transformando conteúdo <code>&lt;private&gt;</code> em <code>[REDACTED]</code>.</li><li><code>loadConfig()</code>: Carrega arquivo de configuração local, prioridade mais alta que variáveis de ambiente.</li></ul></details><h2 id="proxima-licao" tabindex="-1">Próxima Lição <a class="header-anchor" href="#proxima-licao" aria-label="Permalink to &quot;Próxima Lição&quot;">​</a></h2><blockquote><p>Parabéns por completar os cursos principais do opencode-supermemory!</p><p>Em seguida você pode:</p><ul><li>Revisar <a href="/docs/opencodedocs/pt/supermemoryai/opencode-supermemory/advanced/configuration/">Configuração Avançada</a> para mais opções de personalização.</li></ul></blockquote>',35)])])}const g=a(n,[["render",s]]);export{l as __pageData,g as default};
